import requests
from solution import fetch

def test_fetch_has_timeout(monkeypatch):
    calls = []
    def mock_get(url, **kw):
        calls.append(kw)
        class R:
            status_code = 200
        return R()
    monkeypatch.setattr(requests, 'get', mock_get)
    fetch('http://x.com')
    assert calls[0]['timeout'] == 30

