test_code:
from solution import find_user

class Cursor:
    def __init__(self):
        self.calls = []
    def execute(self, query, params=None):
        self.calls.append((query, params))
        return self.calls[-1]

def test_query_is_parameterized():
    cursor = Cursor()
    find_user(cursor, "alice")
    assert cursor.calls[0][1] == ('alice',)

